options.dotDiagram:
digraph "GrafanaGraphviz" {
  graph [
    rankdir = "LR";
    ratio = "compress";
  ];
  edge [
    color = "#8c8f96";
    fontname = "Arial";
    fontsize = "10";
    arrowsize = "0.75";
    penwidth = "1.6";
  ];
  node [
    shape = "box";
    style = "filled";
    fillcolor = "#1d2025";
    color = "#70757d";
    fontcolor = "#e5e7eb";
    fontname = "Arial";
    fontsize = "12";
    margin = "0.14,0.10";
  ];
  "user_input" [
    shape = "plain";
    label = <
      <TABLE BORDER="1" CELLBORDER="1" CELLSPACING="0"
             COLOR="#747982" BGCOLOR="#1d2025">
        <TR>
          <TD WIDTH="105" HEIGHT="40">
            <FONT COLOR="#e5e7eb">👤 User Input</FONT>
          </TD>
        </TR>
        <TR><TD HEIGHT="40">Builder</TD></TR>
        <TR><TD HEIGHT="40">Code</TD></TR>
        <TR><TD HEIGHT="40">Query</TD></TR>
      </TABLE>
    >;
  ];
  subgraph "cluster_graphviz" {
    label = <<I>Graphviz Processing</I>>;
    labelloc = "t";
    labeljust = "c";
    fontsize = "11";
    fontcolor = "#c8c9ca";
    style = "rounded,dashed";
    color = "#71767d";
    penwidth = "1.2";
    bgcolor = "#181b1f";
    margin = "12";
    "dot_parser" [
      label = "DOT Parser\n🔍";
      width = "1.25";
      height = "0.72";
    ];
    "dot_validator" [
      shape = "diamond";
      label = "DOT\nValidator\n✅";
      width = "1.35";
      height = "1.35";
      fixedsize = "true";
      fillcolor = "#1d2025";
    ];
    "layout_engines" [
      shape = "plain";
      label = <
        <TABLE BORDER="1" CELLBORDER="1" CELLSPACING="0"
               COLOR="#747982" BGCOLOR="#1d2025">
          <TR>
            <TD WIDTH="130" HEIGHT="40">
              <FONT COLOR="#e5e7eb">🎯 Layout Engines</FONT>
            </TD>
          </TR>
          <TR><TD HEIGHT="40">Hierarchical</TD></TR>
          <TR><TD HEIGHT="40">Network</TD></TR>
          <TR><TD HEIGHT="40">Force-Directed</TD></TR>
          <TR><TD HEIGHT="40">Circular</TD></TR>
        </TABLE>
      >;
    ];
    "dot_parser" -> "dot_validator" [
      dir = "both";
      color = "#8172d8";
      arrowhead = "normal";
      arrowtail = "normal";
    ];
    "dot_parser" -> "layout_engines" [
      color = "#4c9aee";
      penwidth = "2.0";
      minlen = "2";
    ];
    "dot_validator" -> "layout_engines" [
      color = "#4c9aee";
      style = "dotted";
      penwidth = "1.8";
    ];
  }
  subgraph "cluster_rendering" {
    label = <<I>Panel Rendering Pipeline</I>>;
    labelloc = "t";
    labeljust = "c";
    fontsize = "11";
    fontcolor = "#c8c9ca";
    style = "rounded,dashed";
    color = "#71767d";
    penwidth = "1.2";
    bgcolor = "#181b1f";
    margin = "14";
    "svg_renderer" [
      label = "SVG Renderer\n🎨";
      width = "1.35";
      height = "0.75";
    ];
    "theme_system" [
      label = "Theme System\n◐";
      width = "1.4";
      height = "0.75";
    ];
    "hover_handlers" [
      label = "Hover & Click\nHandlers 🖱";
      width = "1.4";
      height = "0.75";
    ];
    "position_calculator" [
      label = "Position\nCalculator\n📐";
      width = "1.3";
      height = "1.05";
    ];
    "interactive_diagram" [
      label = "Interactive\nGraphviz\nDiagram\n✨";
      width = "1.5";
      height = "1.25";
      style = "rounded,filled";
      penwidth = "2.2";
      color = "#858a91";
      fillcolor = "#20242a";
    ];
    "svg_renderer" -> "theme_system" [
      color = "#6ac94c";
      penwidth = "1.8";
    ];
    "svg_renderer" -> "hover_handlers" [
      color = "#d5a22c";
      penwidth = "1.8";
    ];
    "svg_renderer" -> "position_calculator" [
      color = "#f0a026";
      penwidth = "2.0";
    ];
    "theme_system" -> "interactive_diagram" [
      color = "#ef572a";
      penwidth = "2.0";
    ];
    "hover_handlers" -> "interactive_diagram" [
      color = "#d73fc4";
      penwidth = "2.0";
    ];
    "position_calculator" -> "hover_handlers" [
      color = "#f0a026";
      dir = "both";
      penwidth = "1.8";
    ];
    "position_calculator" -> "interactive_diagram" [
      color = "#d83b49";
      penwidth = "2.0";
    ];
  }
  subgraph "cluster_grafana" {
    label = <<I>Grafana Data Integration</I>>;
    labelloc = "t";
    labeljust = "c";
    fontsize = "11";
    fontcolor = "#c8c9ca";
    style = "rounded,dashed";
    color = "#71767d";
    penwidth = "1.2";
    bgcolor = "#181b1f";
    margin = "12";
    "grafana_datasources" [
      shape = "cylinder";
      label = "Grafana\nDatasource(s)\n📊";
      width = "1.5";
      height = "1.05";
    ];
    "live_bindings" [
      shape = "plain";
      label = <
        <TABLE BORDER="1" CELLBORDER="1" CELLSPACING="0"
               COLOR="#747982" BGCOLOR="#1d2025">
          <TR>
            <TD WIDTH="150" HEIGHT="42">
              <FONT COLOR="#e5e7eb">🔗 Live Data Bindings</FONT>
            </TD>
          </TR>
          <TR><TD HEIGHT="40">Color Overrides</TD></TR>
          <TR><TD HEIGHT="40">Label Interpolation</TD></TR>
          <TR><TD HEIGHT="40">Tooltips &amp; Datalinks</TD></TR>
        </TABLE>
      >;
    ];
    "grafana_datasources" -> "live_bindings" [
      color = "#55b8ad";
      style = "dotted";
      penwidth = "1.8";
    ];
  }
  subgraph {
    rank = "same";
    "user_input";
    "dot_parser";
    "dot_validator";
    "layout_engines";
    "svg_renderer";
    "hover_handlers";
    "position_calculator";
  }
  "user_input" -> "dot_parser" [
    color = "#d47ca2";
    penwidth = "1.8";
  ];
  "layout_engines" -> "svg_renderer" [
    color = "#4bb3a9";
    penwidth = "1.8";
  ];
  "live_bindings" -> "theme_system" [
    color = "#8cab38";
    style = "dotted";
    penwidth = "1.8";
  ];
  "live_bindings" -> "hover_handlers" [
    color = "#d6a128";
    style = "dotted";
    penwidth = "1.8";
  ];
  "live_bindings" -> "interactive_diagram" [
    color = "#cb6146";
    style = "dotted";
    penwidth = "1.8";
  ];
  "grafana_datasources" -> "live_bindings" [
    weight = "5";
  ];
  "layout_engines" -> "grafana_datasources" [
    style = "invis";
    weight = "2";
  ];
  "theme_system" -> "live_bindings" [
    style = "invis";
    weight = "1";
  ];
  "Server 1" -> "node4" [
    id = "node";
  ];
}
